import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { dashboardAPI } from '../../services/api';
import Card from '../../components/common/Card';
import StatCard from '../../components/common/StatCard';
import { Users, ClipboardList, BookOpen, CheckCircle } from 'lucide-react';

const TeacherDashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await dashboardAPI.getStats();
      if (response.data.success) {
        setStats(response.data.stats);
      }
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="text-center py-10">Loading...</div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Welcome Header */}
      <div className="bg-gradient-to-r from-blue-600 to-blue-700 rounded-xl p-6 text-white">
        <h1 className="text-2xl font-bold mb-1">
          Welcome, {user?.firstName}!
        </h1>
        <p className="text-blue-100">
          {stats?.advisorySection && `Advisory: Section ${stats.advisorySection}`}
          {stats?.isCapstoneAdviser && ' | Capstone Adviser Available'}
        </p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatCard
          title="Advisory Students"
          value={stats?.advisoryCount || 0}
          icon={Users}
          color="blue"
        />
        <StatCard
          title="Violations Encoded"
          value={stats?.violationsEncoded || 0}
          icon={ClipboardList}
          color="orange"
        />
        <StatCard
          title="Capstone Requests"
          value={stats?.capstoneRequests || 0}
          icon={BookOpen}
          color="purple"
        />
        <StatCard
          title="Capstone Status"
          value={stats?.isCapstoneAdviser ? 'Available' : 'Unavailable'}
          icon={CheckCircle}
          color={stats?.isCapstoneAdviser ? 'green' : 'red'}
        />
      </div>

      {/* Recent Violations */}
      <Card title="Recent Violations Encoded">
        {stats?.recentViolations?.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-secondary-200">
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Student</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Violation</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Date</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Status</th>
                </tr>
              </thead>
              <tbody>
                {stats.recentViolations.map((violation) => (
                  <tr key={violation.id} className="border-b border-secondary-100 hover:bg-secondary-50">
                    <td className="py-3 px-4">
                      {violation.first_name} {violation.last_name}
                      <span className="text-secondary-500 text-sm ml-2">({violation.student_id})</span>
                    </td>
                    <td className="py-3 px-4">{violation.violation_type}</td>
                    <td className="py-3 px-4">{violation.date}</td>
                    <td className="py-3 px-4">
                      <span className={`px-3 py-1 rounded-full text-sm ${
                        violation.status === 'Pending'
                          ? 'bg-yellow-100 text-yellow-700'
                          : 'bg-green-100 text-green-700'
                      }`}>
                        {violation.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="text-center py-8 text-secondary-500">
            <ClipboardList className="w-12 h-12 mx-auto mb-3 text-secondary-300" />
            <p>No violations encoded yet</p>
          </div>
        )}
      </Card>
    </div>
  );
};

export default TeacherDashboard;
